#!/bin/bash
set -e
echo "🚀 Deploy v14: Performance Optimizations"
echo "  A. Parallel AI visibility queries (ThreadPoolExecutor)"
echo "  B. Parallel PSI mobile+desktop"
echo "  D. Concurrent module execution in runner"
echo "  E. 24h Perplexity response cache"
echo "  F. Single Perplexity call per query (32→8 API calls)"
echo "  + Fix: Performance recommendations always show"
echo ""

cd ~/chaos_tester
echo '📄 Writing runner.py...'
echo '' | base64 -d > runner.py

echo '📄 Writing modules/performance.py...'
echo '' | base64 -d > modules/performance.py

echo '📄 Writing modules/ai_visibility.py...'
echo '' | base64 -d > modules/ai_visibility.py

# Verify Python syntax
echo ""
echo "🔍 Verifying Python syntax..."
python3 -c "import py_compile; py_compile.compile('runner.py', doraise=True); print('  runner.py ✓')"
python3 -c "import py_compile; py_compile.compile('modules/performance.py', doraise=True); print('  performance.py ✓')"
python3 -c "import py_compile; py_compile.compile('modules/ai_visibility.py', doraise=True); print('  ai_visibility.py ✓')"

# Update Dockerfile cache bust
echo "📦 Updating Dockerfile cache bust..."
sed -i 's/^ARG CACHE_BUST=.*/ARG CACHE_BUST=1773524424/' Dockerfile
if ! grep -q 'ARG CACHE_BUST' Dockerfile; then
  sed -i '/^COPY \. \.\/chaos_tester\//i ARG CACHE_BUST=1773524424' Dockerfile
fi

# Remove duplicate chaos_tester/ subdirectory if it exists
if [ -d "chaos_tester" ]; then
  echo "🧹 Removing duplicate chaos_tester/ subdirectory..."
  rm -rf chaos_tester/
fi

# Commit and push
echo "📤 Committing and pushing to GitHub..."
git add -A
git commit -m "perf: concurrent execution + reduce Perplexity API calls 4x

- Runner: all modules execute concurrently after availability phase
- AI Visibility: 1 Perplexity call per query shared across 4 platforms (32→8 calls)
- AI Visibility: concurrent query execution via ThreadPoolExecutor
- AI Visibility: 24h in-memory response cache with auto-eviction
- PSI: mobile + desktop fetched concurrently
- Performance recommendations: lower thresholds + metric-based fallbacks
- Expected audit time: ~15-20s (was ~100s+)"
git push origin main

# Deploy to Cloud Run
echo "☁️ Deploying to Cloud Run..."
gcloud run deploy chaos-tester \
  --source . \
  --region us-central1 \
  --allow-unauthenticated \
  --port 8080 \
  --memory 512Mi

echo ""
echo "✅ Deploy v14 complete! Run an audit to test the speed improvement."
